// This code analyzes the manuscript to determine the next chapter number

// Safely get the manuscript text
let manuscriptText = "";
try {
  // Access the input data safely
  if ($input && $input.item && $input.item.json && $input.item.json.content) {
    manuscriptText = $input.item.json.content;
    console.log("Successfully got manuscript, length:", manuscriptText.length);
  } else {
    console.log("Manuscript content not found in input");
  }
} catch (error) {
  console.log("Error accessing manuscript:", error.message || "Unknown error");
}

// Look for chapter markers in the manuscript
const chapters = [];
try {
  // Use regex to find both formats of chapter markers
  const chapterPatterns = [
    /\[BEGIN CHAPTER (\d+)\]([\s\S]*?)\[END CHAPTER \1\]/gi,
    /\[BEGIN MOP CHAPTER (\d+)\]([\s\S]*?)\[END MOP CHAPTER \1\]/gi
  ];

  for (const pattern of chapterPatterns) {
    let match;
    while ((match = pattern.exec(manuscriptText)) !== null) {
      const chapterNum = parseInt(match[1]);
      if (!chapters.some(ch => ch.number === chapterNum)) {
        chapters.push({
          number: chapterNum,
          content: match[0]
        });
        console.log(`Found completed chapter ${chapterNum}`);
      }
    }
  }
} catch (error) {
  console.log("Error extracting chapters:", error.message || "Unknown error");
}

// Sort chapters by number
chapters.sort((a, b) => a.number - b.number);

// Safely get total chapters from form input
let totalChapters = 11; // Default value
try {
  const formNode = $('On form submission');
  if (formNode && formNode.item && formNode.item.json) {
    const inputTotal = formNode.item.json['Total # Chapters'];
    if (inputTotal) {
      const parsed = parseInt(inputTotal);
      if (!isNaN(parsed)) {
        totalChapters = parsed;
      }
    }
  }
} catch (error) {
  console.log("Error getting total chapters:", error.message || "Unknown error");
}
console.log(`Total chapters target: ${totalChapters}`);

// Determine next chapter to process and completion status
const nextChapterNumber = chapters.length > 0 ? 
  chapters[chapters.length - 1].number + 1 : 1;
const isComplete = nextChapterNumber > totalChapters;
const progressPercent = Math.round((chapters.length / totalChapters) * 100);

console.log(`Next chapter to process: ${nextChapterNumber}`);
console.log(`Is manuscript complete: ${isComplete} (${progressPercent}% done)`);

// Build the target chapter name for searching
const targetChapterName = `Chapter ${nextChapterNumber} Draft`;

// Extract the last 4 chapters for context
const recentChapters = chapters.slice(Math.max(0, chapters.length - 4));
console.log(`Recent chapters (last ${recentChapters.length}): ${recentChapters.map(ch => ch.number).join(', ')}`);

// Return results
return {
  json: {
    nextChapterNumber: nextChapterNumber,
    targetChapterName: targetChapterName,
    isComplete: isComplete,
    totalChapters: totalChapters,
    completedCount: chapters.length,
    progressPercent: progressPercent,
    recentChapters: recentChapters,
    isFirstChapter: chapters.length === 0,
    lastChapterContent: recentChapters.length > 0 ? recentChapters[recentChapters.length - 1].content : ""
  }
};

const files = $("Edit Fields")
  .all()
  .map((item) => item.json);
const targetChapterName = $("Determine Next Chapter").all()[0]?.json
  ?.targetChapterName;

const targetFile = files.find((file) => file.name === targetChapterName);

return { targetFile };

// Get values from the Determine Next Chapter node's output
let nextChapterNumber, totalChapters;

try {
  // Get the original next chapter number from the Determine Next Chapter node
  const determineNode = $('Determine Next Chapter');
  if (determineNode && determineNode.item && determineNode.item.json) {
    // This is the chapter number we just processed
    const currentChapterNumber = determineNode.item.json.nextChapterNumber;
    totalChapters = determineNode.item.json.totalChapters;

    // Set nextChapterNumber to the next chapter (current + 1)
    nextChapterNumber = currentChapterNumber + 1;

    console.log(`Current chapter processed: ${currentChapterNumber}`);
    console.log(`Next chapter will be: ${nextChapterNumber}`);
  } else {
    console.log("Could not access Determine Next Chapter node data");
    // Default values if we can't access the node
    nextChapterNumber = 2; // Assume we just processed chapter 1
    totalChapters = 11;    // Default to 11 chapters
  }
} catch (error) {
  console.log("Error accessing Determine Next Chapter data:", error.message);
  // Default values if there's an error
  nextChapterNumber = 2;
  totalChapters = 11;
}

// Alternative approach: try to get the chapter number from the Draft MOP Chapter content
try {
  const draftNode = $('Draft MOP Chapter');
  if (draftNode && draftNode.item && draftNode.item.json && draftNode.item.json.text) {
    const draftText = draftNode.item.json.text;

    // Try to extract chapter number from BEGIN CHAPTER tag
    const chapterMatch = draftText.match(/\[BEGIN CHAPTER (\d+)\]/i);
    if (chapterMatch && chapterMatch[1]) {
      const chapterFromDraft = parseInt(chapterMatch[1]);
      console.log(`Found chapter number ${chapterFromDraft} in Draft MOP Chapter content`);

      // Use this as a cross-check
      if (chapterFromDraft + 1 !== nextChapterNumber) {
        console.log(`WARNING: Chapter number mismatch - Draft says ${chapterFromDraft}, Determine Next Chapter implies next is ${nextChapterNumber}`);
        // Trust the draft content over the determine node
        nextChapterNumber = chapterFromDraft + 1;
      }
    }
  }
} catch (error) {
  console.log("Error checking Draft MOP Chapter content:", error.message);
}

// Calculate completion status and progress
const isComplete = nextChapterNumber > totalChapters;
const progressPercent = Math.round(((nextChapterNumber - 1) / totalChapters) * 100);

console.log(`Next chapter will be: ${nextChapterNumber}`);
console.log(`Total chapters: ${totalChapters}`);
console.log(`Is complete: ${isComplete}`);
console.log(`Progress: ${progressPercent}%`);

// Return results
return {
  json: {
    nextChapterNumber,
    isComplete,
    totalChapters,
    progressPercent
  }
};

// Get data from the Determine Next Chapter node which already has the chapter information
let nextChapterNumber = 1;
let recentChapters = [];
let lastChapterContent = "";

try {
  const determineNode = $('Determine Next Chapter');
  if (determineNode && determineNode.item && determineNode.item.json) {
    // Extract information directly from the Determine Next Chapter node
    nextChapterNumber = determineNode.item.json.nextChapterNumber || 1;
    console.log(`Next chapter from Determine Next Chapter: ${nextChapterNumber}`);

    // Get recent chapters if available
    if (determineNode.item.json.recentChapters && Array.isArray(determineNode.item.json.recentChapters)) {
      recentChapters = determineNode.item.json.recentChapters;
      console.log(`Found ${recentChapters.length} recent chapters from Determine Next Chapter`);
    }

    // Get last chapter content if available
    if (determineNode.item.json.lastChapterContent) {
      lastChapterContent = determineNode.item.json.lastChapterContent;
      console.log(`Last chapter content length: ${lastChapterContent.length} chars`);
    }
  } else {
    console.log("Could not access Determine Next Chapter node data");
  }
} catch (error) {
  console.log("Error accessing Determine Next Chapter data:", error.message);
}

// Get manuscript content for debugging
let manuscriptText = "";
try {
  if ($input && $input.item && $input.item.json && $input.item.json.content) {
    manuscriptText = $input.item.json.content;
    console.log(`Manuscript length: ${manuscriptText.length} chars`);

    // Debug: Check if manuscript contains chapter markers
    if (manuscriptText.includes("[BEGIN CHAPTER")) {
      console.log("Manuscript contains [BEGIN CHAPTER markers");
    } else {
      console.log("Manuscript does NOT contain [BEGIN CHAPTER markers");
    }
  }
} catch (error) {
  console.log("Error accessing manuscript:", error.message);
}

// Format recent chapters as context string
let recentChaptersText = "";
if (recentChapters.length > 0) {
  recentChaptersText = "### Recent Chapters for Context:\n\n";
  recentChapters.forEach(chapter => {
    recentChaptersText += `Chapter ${chapter.number}:\n${chapter.content}\n\n`;
  });
  console.log(`Generated recent chapters text: ${recentChaptersText.length} chars`);
} else {
  // Always provide at least the last chapter content if we have it
  if (lastChapterContent && lastChapterContent.length > 0) {
    const chapterNumber = nextChapterNumber - 1;
    recentChaptersText = `### Recent Chapters for Context:\n\nChapter ${chapterNumber}:\n${lastChapterContent}\n\n`;
    console.log(`Generated context from lastChapterContent: ${recentChaptersText.length} chars`);
  } else {
    recentChaptersText = "### No Recent Chapters Available\n\n";
    console.log("No chapters available for context");
  }
}

// Create the dynamic context
const dynamicContext = recentChaptersText;

// Return everything with more detailed information for debugging
return {
  json: {
    nextChapterNumber,
    isFirstChapter: recentChapters.length === 0 && !lastChapterContent,
    recentChaptersText,
    dynamicContext,
    lastChapterContent,
    recentChaptersCount: recentChapters.length,
    totalChaptersFound: recentChapters.length,
    debug: {
      manuscriptLength: manuscriptText.length,
      hasBeginChapterMarkers: manuscriptText.includes("[BEGIN CHAPTER"),
      determineNodeData: {
        available: !!$('Determine Next Chapter')?.item?.json,
        nextChapter: $('Determine Next Chapter')?.item?.json?.nextChapterNumber,
        chaptersFound: !!$('Determine Next Chapter')?.item?.json?.recentChapters
      }
    }
  }
};
